mapper.select:
SELECT * FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT th.history_id, th.task_id, t.project_id AS projectId, p.project_title AS projectTitle, u.user_name AS userName, NVL(d_title.new_value, t.task_title) AS taskTitle, NVL(d_type.new_value, tt.type_name) AS typeName, cc.default_describe AS defaultDescribe, th.action_type, th.action_at FROM task_history th INNER JOIN task t ON th.task_id = t.task_id INNER JOIN users u ON th.changed_by = u.user_code INNER JOIN task_types tt ON t.type_id = tt.type_id LEFT JOIN project p ON t.project_id = p.project_id LEFT JOIN task_history_detail d_title ON th.history_id = d_title.history_id AND d_title.field_name = 'task_title' LEFT JOIN task_history_detail d_type ON th.history_id = d_type.history_id AND d_type.field_name = 'type_name' LEFT OUTER JOIN common_code cc ON t.task_status = cc.common_id AND cc.common_code = '0E'
AND t.project_id = #{projectId}
AND u.user_code = #{userCode}
AND th.action_at >= TO_DATE(#{startDate}, 'YYYY.MM.DD')
AND th.action_at < TO_DATE(#{endDate}, 'YYYY.MM.DD') + INTERVAL '1' DAY
AND NVL(d_type.new_value, tt.type_name) IN
#{type}
UNION ALL
SELECT NULL AS history_id, w.wiki_page_id AS task_id, w.project_id AS projectId, p2.project_title AS projectTitle, u2.user_name AS userName, w.title AS taskTitle, '위키' AS typeName, '위키 생성' AS defaultDescribe, 'CREATE' AS action_type, w.created_at AS action_at FROM wiki_pages w JOIN users u2 ON w.user_code = u2.user_code LEFT JOIN project p2 ON w.project_id = p2.project_id
AND w.project_id = #{projectId}
AND u2.user_code = #{userCode}
AND w.created_at >= TO_DATE(#{startDate}, 'YYYY.MM.DD')
AND w.created_at < TO_DATE(#{endDate}, 'YYYY.MM.DD') + INTERVAL '1' DAY
UNION ALL
SELECT NULL, wp.wiki_page_id, wp.project_id, p3.project_title, u3.user_name, h.title, '위키', '위키 수정', 'UPDATE', h.created_at FROM wiki_histories h JOIN wiki_pages wp ON h.wiki_page_id = wp.wiki_page_id JOIN users u3 ON h.user_code = u3.user_code LEFT JOIN project p3 ON wp.project_id = p3.project_id
AND wp.project_id = #{projectId}
AND u3.user_code = #{userCode}
AND h.created_at >= TO_DATE(#{startDate}, 'YYYY.MM.DD')
AND h.created_at < TO_DATE(#{endDate}, 'YYYY.MM.DD') + INTERVAL '1' DAY
ORDER BY action_at DESC ) inner_q WHERE ROWNUM <= #{offset} + #{pageSize} ) WHERE rn > #{offset}

SELECT * FROM ( SELECT th.history_id, th.task_id, t.project_id AS projectId, p.project_title AS projectTitle, u.user_name AS userName, NVL(d_title.new_value, t.task_title) AS taskTitle, NVL(d_type.new_value, tt.type_name) AS typeName, cc.default_describe AS defaultDescribe, th.action_type, th.action_at AS actionAt FROM task_history th INNER JOIN task t ON th.task_id = t.task_id INNER JOIN users u ON th.changed_by = u.user_code INNER JOIN task_types tt ON t.type_id = tt.type_id LEFT JOIN project p ON t.project_id = p.project_id LEFT JOIN task_history_detail d_title ON th.history_id = d_title.history_id AND d_title.field_name = 'task_title' LEFT JOIN task_history_detail d_type ON th.history_id = d_type.history_id AND d_type.field_name = 'type_name' LEFT OUTER JOIN common_code cc ON t.task_status = cc.common_id AND cc.common_code = '0E'
TO_CHAR(th.action_at, 'YYYY-MM-DD') = #{targetDate}
AND t.project_id = TO_NUMBER(#{projectId})
AND u.user_code = #{userCode}
AND NVL(d_type.new_value, tt.type_name) IN
#{type}
UNION ALL
SELECT NULL, w.wiki_page_id, w.project_id, p2.project_title, u2.user_name, w.title, '위키', '위키 생성', 'CREATE', w.created_at FROM wiki_pages w JOIN users u2 ON w.user_code = u2.user_code LEFT JOIN project p2 ON w.project_id = p2.project_id WHERE TO_CHAR(w.created_at, 'YYYY-MM-DD') = #{targetDate} AND w.project_id = TO_NUMBER(#{projectId}) AND u2.user_code = #{userCode}
UNION ALL
SELECT NULL, wp.wiki_page_id, wp.project_id, p3.project_title, u3.user_name, h.title, '위키', '위키 수정', 'UPDATE', h.created_at FROM wiki_histories h JOIN wiki_pages wp ON h.wiki_page_id = wp.wiki_page_id JOIN users u3 ON h.user_code = u3.user_code LEFT JOIN project p3 ON wp.project_id = p3.project_id WHERE TO_CHAR(h.created_at, 'YYYY-MM-DD') = #{targetDate} AND wp.project_id = TO_NUMBER(#{projectId}) AND u3.user_code = #{userCode}
) ORDER BY 10 DESC
